package genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_schedule.service.MaintenanceScheduleService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-schedules") public class MaintenanceScheduleController { private final MaintenanceScheduleService service; public MaintenanceScheduleController(MaintenanceScheduleService service){this.service=service;} @GetMapping public List<MaintenanceScheduleResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceScheduleResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceScheduleResponse create(@RequestBody MaintenanceScheduleUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceScheduleResponse update(@PathVariable UUID id,@RequestBody MaintenanceScheduleUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
